mapper.select:
SELECT task_id AS taskId, COUNT(student_id) AS partakeCount FROM student_exam_score WHERE deleted = 0 AND task_id IN
#{item}
GROUP BY task_id

SELECT score.id AS id, stu.id AS studentId, stu.seat_no AS seatNo, stu.chinese_name AS chineseName, stu.english_name AS englishName, stu.display_name_type AS displayNameType, stu.student_no AS studentNo, task.subject_id AS subjectId, subject.subject_name AS subjectName, task.id AS taskId, task.name AS taskName, stu.student_no AS studentNo, sem.name AS periodName, score.score AS score FROM student_exam_score score LEFT JOIN student_exam_task task ON task.id = score.task_id LEFT JOIN subject_rel srl ON srl.id = task.subject_id LEFT JOIN subject subject ON subject.id = srl.subject_id LEFT JOIN sys_semester sem ON sem.id = task.period_id LEFT JOIN student_info stu ON stu.id = score.student_id WHERE score.deleted = 0 AND task.deleted = 0
AND score.student_id = #{studentId}
AND score.task_id IN
#{item}

SELECT score.student_id AS studentId, task.period_id AS periodId, task.subject_id AS subjectId, score.score AS score FROM student_exam_score score LEFT JOIN student_exam_task task ON task.id = score.task_id WHERE task.class_id = #{classId}
AND task.period_id = #{periodId}
AND score.deleted = 0 AND task.deleted = 0 ORDER BY score.student_id ASC

SELECT task.subject_id AS subjectId, s.subject_name AS subjectName, sr.subject_type AS subjectType, score.score AS score FROM student_exam_score score LEFT JOIN student_exam_task task ON task.id = score.task_id AND task.deleted = 0 LEFT JOIN subject_rel sr ON sr.id = task.subject_id AND sr.deleted = 0 LEFT JOIN `subject` s ON s.id = sr.subject_id AND s.deleted = 0 WHERE score.deleted = 0 AND score.student_id = ${reqModel.studentId}
AND task.period_id = ${reqModel.semesterId}
AND sr.subject_id = ${reqModel.subjectId}
ORDER BY task.id DESC
